## Testing Requirements

### Unit Tests (`__tests__/replay-recording.test.ts`)

```typescript
describe('ReplayRecording', () => {
  describe('frame capture', () => {
    it('should capture input frame with correct structure', () => {
      const frame = captureFrame('input', { prompt: 'Hello' }, context);
      expect(frame.type).toBe('input');
      expect(frame.content).toEqual({ prompt: 'Hello' });
      expect(frame.context.tokenUsage).toBeDefined();
    });

    it('should link tool_result to tool_call', () => {
      const callFrame = captureFrame('tool_call', { tool: 'read' }, context);
      const resultFrame = captureFrame('tool_result', { result: 'file content' }, context, {
        toolCallId: callFrame.toolCallId
      });
      expect(resultFrame.toolCallId).toBe(callFrame.toolCallId);
    });

    it('should capture error with stack trace', () => {
      const error = new Error('Something failed');
      const frame = captureFrame('error', { error }, context);
      expect(frame.content.stack).toBeDefined();
    });
  });

  describe('errors_only mode', () => {
    it('should only persist frames when error occurs', async () => {
      const session = startRecording('agent-1', 'errors_only');
      captureFrame('input', {}, context); // Not persisted yet
      captureFrame('output', {}, context); // Not persisted yet
      captureFrame('error', { error: 'fail' }, context);

      const persisted = await getPersistedFrames(session.id);
      expect(persisted.length).toBeGreaterThan(0); // Now persisted
    });

    it('should keep last N frames before error', async () => {
      const session = startRecording('agent-1', 'errors_only', { bufferSize: 10 });
      for (let i = 0; i < 20; i++) {
        captureFrame('output', { i }, context);
      }
      captureFrame('error', { error: 'fail' }, context);

      const persisted = await getPersistedFrames(session.id);
      expect(persisted.length).toBe(11); // 10 buffer + 1 error
    });
  });

  describe('sampling mode', () => {
    it('should capture every Nth frame', async () => {
      const session = startRecording('agent-1', 'sampling', { sampleRate: 5 });
      for (let i = 0; i < 20; i++) {
        captureFrame('output', { i }, context);
      }

      const persisted = await getPersistedFrames(session.id);
      expect(persisted.length).toBe(4); // 0, 5, 10, 15
    });

    it('should always capture errors regardless of sampling', async () => {
      const session = startRecording('agent-1', 'sampling', { sampleRate: 100 });
      for (let i = 0; i < 50; i++) {
        captureFrame('output', { i }, context);
      }
      captureFrame('error', { error: 'fail' }, context);

      const persisted = await getPersistedFrames(session.id);
      const errors = persisted.filter(f => f.type === 'error');
      expect(errors.length).toBe(1);
    });
  });
});
```

