test.describe('Agent Replay', () => {
  test('should record and replay session', async ({ page }) => {
    // Start agent with recording
    await page.goto('/agents/test-agent');
    await page.click('[data-testid="start-recording"]');
    await page.click('[data-testid="run-agent"]');
    await page.waitForSelector('[data-testid="agent-completed"]');
    await page.click('[data-testid="stop-recording"]');

    // Open replay
    await page.goto('/replays');
    await page.click('[data-testid="replay-row"]:first-child');

    // Verify replay UI
    await expect(page.locator('[data-testid="replay-player"]')).toBeVisible();
    await expect(page.locator('[data-testid="timeline"]')).toBeVisible();

    // Step through frames
    await page.click('[data-testid="step-forward"]');
    await expect(page.locator('[data-testid="frame-inspector"]')).toBeVisible();
  });

  test('should jump to error in replay', async ({ page }) => {
    await page.goto('/replays/session-with-error');
    await page.click('[data-testid="jump-to-error"]');

    const frame = page.locator('[data-testid="current-frame"]');
    await expect(frame).toHaveAttribute('data-type', 'error');
  });

  test('should add and view annotations', async ({ page }) => {
    await page.goto('/replays/session-1');
    await page.click('[data-testid="add-annotation"]');
    await page.fill('[data-testid="annotation-text"]', 'Bug starts here');
    await page.click('[data-testid="save-annotation"]');

    await expect(page.locator('[data-testid="annotation-marker"]')).toBeVisible();
  });
});
