describe("Data hooks - development mode behavior", () => {
  beforeAll(() => {
    process.env.NODE_ENV = "development";
    console.log("[TEST] Running in development mode");
  });

  it("should use mock data in development when API fails", async () => {
    server.use(
      rest.get("/api/snapshot", (req, res, ctx) => res(ctx.status(500)))
    );

    const { result, waitFor } = renderHook(() => useSnapshot());
    await waitFor(() => \!result.current.isLoading);

    expect(result.current.usingMockData).toBe(true);
    expect(result.current.data).toBeDefined();  // Mock data provided
    expect(result.current.error).toBeDefined(); // But error still set\!
    console.log("[TEST] PASS: Dev mode uses mock data but preserves error");
  });

  it("should indicate mock data is being used via flag", async () => {
    server.use(
      rest.get("/api/snapshot", (req, res, ctx) => res(ctx.status(500)))
    );

    const { result, waitFor } = renderHook(() => useSnapshot());
    await waitFor(() => \!result.current.isLoading);

    expect(result.current.usingMockData).toBe(true);
    console.log("[TEST] usingMockData flag is set correctly");
  });
});
```

