## Testing Requirements

### Unit Tests (`__tests__/context-heatmap.test.ts`)

```typescript
describe('ContextHeatMap', () => {
  describe('aggregation', () => {
    it('should aggregate attributions into buckets', () => {
      const attributions = [
        { turn: 1, category: 'tool_call', tokens: 100 },
        { turn: 1, category: 'tool_result', tokens: 500 },
        { turn: 2, category: 'assistant', tokens: 200 },
      ];
      const buckets = aggregateToBuckets(attributions, { bucketSize: 1 });

      expect(buckets[0].attributions.tool_call).toBe(100);
      expect(buckets[0].attributions.tool_result).toBe(500);
      expect(buckets[1].attributions.assistant).toBe(200);
    });

    it('should calculate cumulative tokens', () => {
      const buckets = aggregateToBuckets(attributions, { bucketSize: 1 });
      expect(buckets[0].cumulativeTokens).toBe(600);
      expect(buckets[1].cumulativeTokens).toBe(800);
    });

    it('should mark warning and critical thresholds', () => {
      const buckets = aggregateToBuckets(attributions, { 
        contextLimit: 1000,
        warningThreshold: 0.8,
        criticalThreshold: 0.95
      });

      const warningBucket = buckets.find(b => b.utilization > 0.8);
      expect(warningBucket?.isWarning).toBe(true);
    });
  });

  describe('category breakdown', () => {
    it('should calculate percentages correctly', () => {
      const breakdown = calculateBreakdown(attributions);
      expect(breakdown.tool_result.percentage).toBeCloseTo(62.5); // 500/800
    });
  });
});
```

### Integration Tests (`__tests__/context-heatmap.integration.test.ts`)

```typescript
describe('Context HeatMap API', () => {
  it('GET /api/agents/:id/context-heatmap returns valid data', async () => {
    const res = await app.request('/api/agents/agent-1/context-heatmap');
    const body = await res.json();

    expect(body.buckets).toBeInstanceOf(Array);
    expect(body.totalTokens).toBeGreaterThan(0);
    expect(body.peakUtilization).toBeLessThanOrEqual(1);
  });

  it('returns filtered data for category param', async () => {
    const res = await app.request(
      '/api/agents/agent-1/context-heatmap?categories=tool_call,tool_result'
    );
    const body = await res.json();

    body.buckets.forEach(bucket => {
      expect(Object.keys(bucket.attributions)).toEqual(
        expect.arrayContaining(['tool_call', 'tool_result'])
      );
    });
  });
});
```

